function checkGreeting(params) {
  const { sessionId, messageHistory } = params;
  const isFirstMessage = !messageHistory || messageHistory.length === 0;
  return { isFirstMessage, shouldSendGreeting: isFirstMessage };
}

function routeMessage(params) {
  const { classification, confidenceThreshold, maxTurns, currentTurns } = params;
  if (classification.shouldTransferHuman || classification.intent === 'transfer_human') {
    return { target: 'transfer_human', reason: classification.transferReason || '客户要求转人工' };
  }
  if (classification.confidence < confidenceThreshold) {
    return { target: 'transfer_human', reason: '意图识别置信度不足（' + classification.confidence + '）' };
  }
  if (currentTurns >= maxTurns) {
    return { target: 'transfer_human', reason: '对话已超过 ' + maxTurns + ' 轮' };
  }
  var routeMap = { presale: 'presale_specialist', aftersale: 'aftersale_specialist', complaint: 'aftersale_specialist', general: 'self_reply' };
  return { target: routeMap[classification.intent] || 'transfer_human', reason: classification.reasoning };
}

function checkTransfer(params) {
  var answer = params.answer;
  var confidenceThreshold = params.confidenceThreshold;
  if (answer.suggestTransfer || answer.confidence < confidenceThreshold) {
    return { shouldTransfer: true, reason: answer.transferReason || '知识库无相关内容', reply: '抱歉，关于这个问题我需要转接人工客服为您解答，请稍候。' };
  }
  return { shouldTransfer: false, reply: answer.answer };
}

function createTicketIfNeeded(params) {
  var response = params.response;
  var employeeId = params.employeeId;
  var sessionId = params.sessionId;
  var customerMessage = params.customerMessage;
  if (!response.needsTicket) {
    return { ticketCreated: false };
  }
  var ticketData = {
    employeeId: employeeId,
    triggerType: 'event',
    status: response.needsApproval ? 'hitl_waiting' : 'pending',
    input: { sessionId: sessionId, customerMessage: customerMessage, problemType: response.problemType },
    output: { ticketSummary: response.ticketSummary },
    requiresReview: response.needsApproval
  };
  var replyAppend = response.needsApproval ? '\n\n您的请求已提交，需要人工确认后处理，请耐心等待。' : '\n\n已为您创建工单，我们会尽快处理。';
  return { ticketCreated: true, ticketData: ticketData, replyAppend: replyAppend };
}

function prepareConversation(params) {
  var messageHistory = params.messageHistory;
  var startTime = params.startTime;
  var endTime = params.endTime;
  var messages = messageHistory || [];
  var truncated = messages.length > 40 ? messages.slice(-40) : messages;
  var totalTurns = Math.floor(truncated.length / 2);
  var avgResponseTimeMs = endTime && startTime ? (new Date(endTime).getTime() - new Date(startTime).getTime()) / Math.max(totalTurns, 1) : 0;
  var customerMessages = truncated.filter(function(m) { return m.role === 'user'; });
  var botMessages = truncated.filter(function(m) { return m.role === 'assistant'; });
  return {
    conversationText: truncated.map(function(m) { return (m.role === 'user' ? '客户' : 'AI客服') + '：' + m.content; }).join('\n'),
    totalTurns: totalTurns,
    avgResponseTimeMs: avgResponseTimeMs,
    customerMessageCount: customerMessages.length,
    botMessageCount: botMessages.length
  };
}

config.userPrompt:
对话内容：
{{conversation_text}}

统计信息：
- 总轮次：{{total_turns}}
- 平均响应时间：{{avg_response_time_ms}}ms

