function saveQualityReport(params) {
  var evaluation = params.evaluation;
  var sessionId = params.sessionId;
  var employeeId = params.employeeId;
  var alertThreshold = params.alertThreshold;
  var logEntry = {
    employeeId: employeeId,
    logType: 'quality_check',
    content: '会话质检完成 - 综合评分：' + evaluation.overallScore + '分',
    metadata: { sessionId: sessionId, scores: evaluation.scores, overallScore: evaluation.overallScore, highlights: evaluation.highlights, improvements: evaluation.improvements }
  };
  var needsAlert = evaluation.overallScore < alertThreshold || evaluation.needsReview;
  var alertMessage = needsAlert ? '会话 ' + sessionId + ' 质检评分 ' + evaluation.overallScore + ' 分（低于阈值 ' + alertThreshold + '），需要复审。原因：' + (evaluation.reviewReason || evaluation.improvements.join('；')) : '';
  return { logEntry: logEntry, needsAlert: needsAlert, alertMessage: alertMessage };
}

