function createHitlTask(params) {
  var summary = params.summary;
  var sessionId = params.sessionId;
  var employeeId = params.employeeId;
  var notificationChannel = params.notificationChannel;
  var taskData = {
    employeeId: employeeId,
    triggerType: 'event',
    status: 'hitl_waiting',
    input: { sessionId: sessionId, summary: summary },
    output: {},
    requiresReview: true,
    inputSummary: '转人工：' + summary.customerIntent,
    outputSummary: '等待人工处理 - ' + summary.priority + ' 优先级'
  };
  var priorityLabel = summary.priority === 'high' ? '紧急' : '普通';
  var notification = {
    channel: notificationChannel,
    title: '[' + priorityLabel + '] 客户转人工请求',
    content: '客户意图：' + summary.customerIntent + '\n问题概要：' + summary.problemSummary + '\n转人工原因：' + summary.transferReason + '\n建议处理：' + summary.suggestedAction,
    priority: summary.priority
  };
  return { taskData: taskData, notification: notification, customerReply: '正在为您转接人工客服，请稍候。您的问题摘要已发送给客服同事，他们可以直接查看您的对话记录。' };
}
